<template><header class='header'><nav><RouterLink to='/home'>Inicio</RouterLink><RouterLink to='/page/1'>Página 1</RouterLink></nav><div class='controls'><button class='theme' @click='toggleTheme'>Tema</button><select v-model='appConfig.layout'><option value='default'>Normal</option><option value='clean'>Clean</option></select></div></header></template><script setup>import { ref, onMounted } from 'vue'; import { appConfig } from '../store/config'; const isDark=ref(false); onMounted(()=>{isDark.value=document.documentElement.classList.contains('dark');}); const toggleTheme=()=>{isDark.value=!isDark.value; document.documentElement.classList.toggle('dark',isDark.value);};</script><style scoped>.header{display:flex;justify-content:space-between;padding:12px;background:var(--blue-800);}nav a{color:white;margin-right:15px;text-decoration:none;} .controls{display:flex;gap:10px;} .theme{background:none;color:white;border:none;font-size:16px;cursor:pointer;}</style>